This is a complete HTML document that creates an interactive aquarium animation. You can click to drop food, and the fish will swim realistically to chase and eat it.
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>🐠 interactive aquarium · fish & food</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      background: #0b1a2a;
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      font-family: system-ui, 'Segoe UI', Roboto, sans-serif;
    }
    .aquarium-wrapper {
      background: #1c3e4c;
      padding: 18px 18px 22px;
      border-radius: 48px 48px 28px 28px;
      box-shadow: 0 20px 35px rgba(0,0,0,0.7), inset 0 2px 5px rgba(255,255,240,0.3);
      border: 1px solid #7fadc0;
    }
    canvas {
      display: block;
      width: 900px;
      height: 550px;
      border-radius: 28px 28px 18px 18px;
      box-shadow: inset 0 0 40px #04131f, 0 6px 12px rgba(0,0,0,0.5);
      cursor: pointer;
      background: radial-gradient(circle at 20% 30%, #2f7a8c, #154655 75%);
    }
    .info {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin: 12px 10px 0;
      color: #b5dfee;
      font-weight: 500;
      letter-spacing: 0.3px;
      text-shadow: 0 2px 3px #0a1e28;
    }
    .info span {
      background: #1a3a48;
      padding: 6px 18px;
      border-radius: 40px;
      font-size: 0.95rem;
      border: 1px solid #498197;
      box-shadow: inset 0 1px 3px #2e6d82;
    }
    .hint {
      background: #18333e;
      padding: 5px 18px;
      border-radius: 40px;
      font-size: 0.9rem;
      border: 1px solid #4b859b;
    }
  </style>
</head>
<body>
<div class="aquarium-wrapper">
  <canvas id="aquariumCanvas" width="900" height="550"></canvas>
  <div class="info">
    <span>🐟 click to feed</span>
    <span class="hint">🖱️ left click · food</span>
  </div>
</div>
<script>
  (function(){
    const canvas = document.getElementById('aquariumCanvas');
    const ctx = canvas.getContext('2d');

    // ---------- fish parameters ----------
    const FISH_COUNT = 19;  // nice number, varied
    const MAX_SPEED = 1.8;
    const FOOD_ATTRACT_RADIUS = 220; // how far fish see food
    const EAT_DISTANCE = 14;

    // ---------- fish array ----------
    let fish = [];

    // food array
    let foodPellets = [];

    // ---------- utilities ----------
    function random(min, max) {
      return Math.random() * (max - min) + min;
    }

    function clamp(v, min, max) {
      return Math.min(max, Math.max(min, v));
    }

    // ----- fish colors (vibrant) -----
    const colorPalette = [
      { body: '#f6ab6c', fin: '#d98a4a', eye: '#222' },  // orange
      { body: '#ff7979', fin: '#d45c5c', eye: '#2d1b1b' }, // red
      { body: '#7ec8e3', fin: '#469ab4', eye: '#1a3a44' }, // sky
      { body: '#f2e79f', fin: '#d4c26a', eye: '#4d4222' }, // gold
      { body: '#a29bfe', fin: '#6c63d2', eye: '#232049' }, // periwinkle
      { body: '#fd79a8', fin: '#d4507f', eye: '#4d1f32' }, // pink
      { body: '#55efc4', fin: '#2eaa7e', eye: '#145239' }, // mint
      { body: '#fdcb6e', fin: '#e0a83a', eye: '#5a4119' }, // sunflower
      { body: '#e17055', fin: '#b84e38', eye: '#3e1d13' }, // terra
      { body: '#81ecec', fin: '#47b8b8', eye: '#1b4f4f' }, // cyan
      { body: '#d6a2e8', fin: '#a971c4', eye: '#382a45' }, // lilac
    ];

    // ----- create fish -----
    function createFish(index) {
      const palette = colorPalette[index % colorPalette.length];
      const size = random(10, 24);  // varied sizes
      const speedBase = random(0.8, 1.7);
      return {
        x: random(50, 850),
        y: random(50, 500),
        vx: random(-0.8, 0.8),
        vy: random(-0.6, 0.6),
        size: size,
        speed: speedBase,
        // visual
        bodyColor: palette.body,
        finColor: palette.fin,
        eyeColor: palette.eye,
        // wiggle & direction
        angle: random(0, Math.PI * 2),
        tailPhase: random(0, 6.28),
        // personality: slight random offset
        wanderOffset: random(0, 6.28),
        // unique ID just for variety
        id: index,
      };
    }

    function initFish() {
      fish = [];
      for (let i = 0; i < FISH_COUNT; i++) {
        fish.push(createFish(i));
      }
    }
    initFish();

    // ----- food management -----
    function addFood(x, y) {
      // limit max food pieces
      if (foodPellets.length > 35) {
        foodPellets.splice(0, 4);  // remove oldest
      }
      foodPellets.push({
        x: clamp(x, 15, 885),
        y: clamp(y, 15, 535),
        size: random(5, 9),
        opacity: 1.0,
        age: 0
      });
    }

    // ----- helper: distance & closest food -----
    function closestFoodForFish(fx, fy) {
      let minDist = Infinity;
      let target = null;
      for (let f of foodPellets) {
        const dx = f.x - fx;
        const dy = f.y - fy;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist < minDist) {
          minDist = dist;
          target = f;
        }
      }
      return { target, dist: minDist };
    }

    // ----- update fish movement -----
    function updateFish() {
      // first: update food age (dissolve after time, but fish eat first)
      for (let i = foodPellets.length - 1; i >= 0; i--) {
        foodPellets[i].age += 0.016; // ~ per frame
        if (foodPellets[i].age > 9.0) { // fade out after 9 sec
          foodPellets.splice(i,1);
        }
      }

      // fish update
      for (let f of fish) {
        let targetVx = 0, targetVy = 0;
        const lookRadius = FOOD_ATTRACT_RADIUS;

        // ----- food seeking behaviour -----
        const { target: closest, dist: foodDist } = closestFoodForFish(f.x, f.y);
        let foodEaten = false;
        if (closest && foodDist < lookRadius) {
          // direction to food
          const dx = closest.x - f.x;
          const dy = closest.y - f.y;
          const len = Math.sqrt(dx*dx + dy*dy) || 0.001;
          const strength = 1.0 - (foodDist / lookRadius); // 0..1
          const force = 4.8 * strength;

          targetVx += (dx / len) * force;
          targetVy += (dy / len) * force;

          // if close enough => eat
          if (foodDist < EAT_DISTANCE) {
            // remove food
            const idx = foodPellets.indexOf(closest);
            if (idx !== -1) foodPellets.splice(idx, 1);
            foodEaten = true;
          }
        } 
        // ----- if no food detected, wander with gentle drift -----
        else {
          // fish gentle idle wander: sinusoidal & small random walk
          const idleForce = 0.18;
          const angleVar = f.wanderOffset + f.id * 0.9 + Date.now() * 0.0003;
          targetVx += Math.sin(angleVar) * idleForce;
          targetVy += Math.cos(angleVar * 0.7 + 1.2) * idleForce;

          // also add a slight random swim to avoid clumping
          if (Math.random() < 0.01) {
            targetVx += random(-0.4, 0.4);
            targetVy += random(-0.3, 0.3);
          }
        }

        // ----- blending velocity (inertia) -----
        f.vx += (targetVx - f.vx) * 0.06;
        f.vy += (targetVy - f.vy) * 0.06;

        // limit speed
        const sp = Math.sqrt(f.vx*f.vx + f.vy*f.vy);
        const maxSp = f.speed * MAX_SPEED;
        if (sp > maxSp) {
          f.vx = (f.vx / sp) * maxSp;
          f.vy = (f.vy / sp) * maxSp;
        } else if (sp < 0.1 && !closest) {
          // avoid dead stillness
          f.vx += random(-0.08, 0.08);
          f.vy += random(-0.06, 0.06);
        }

        // move fish
        f.x += f.vx;
        f.y += f.vy;

        // ----- tank boundaries (soft bounce) -----
        const margin = 18;
        const right = 882, left = 18, top = 18, bottom = 532;
        if (f.x > right) { f.x = right; f.vx *= -0.6; }
        else if (f.x < left) { f.x = left; f.vx *= -0.6; }
        if (f.y > bottom) { f.y = bottom; f.vy *= -0.6; }
        else if (f.y < top) { f.y = top; f.vy *= -0.6; }

        // update angle for drawing (direction)
        if (Math.abs(f.vx) > 0.02 || Math.abs(f.vy) > 0.02) {
          f.angle = Math.atan2(f.vy, f.vx);
        }
        // tail animation
        f.tailPhase += 0.08 + 0.04 * Math.min(1, Math.sqrt(f.vx*f.vx + f.vy*f.vy) * 0.8);
      }
    }

    // ----- drawing -----
    function drawAquarium() {
      ctx.clearRect(0, 0, 900, 550);

      // water background (already gradient in CSS, but we refine)
      const grad = ctx.createRadialGradient(180, 120, 30, 400, 260, 600);
      grad.addColorStop(0, '#479eb3');
      grad.addColorStop(0.5, '#1f6379');
      grad.addColorStop(1, '#0b3d4f');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, 900, 550);

      // subtle caustics / light beams
      ctx.globalAlpha = 0.08;
      for (let i = 0; i < 12; i++) {
        ctx.beginPath();
        const x = 40 + i * 70 + Math.sin(Date.now()*0.0005 + i)*10;
        ctx.moveTo(x, -10);
        ctx.lineTo(x + 40 + Math.sin(i*2)*10, 560);
        ctx.lineWidth = 16;
        ctx.strokeStyle = '#edf8ff';
        ctx.stroke();
      }
      ctx.globalAlpha = 1.0;

      // draw plants / decoration (simple)
      ctx.shadowColor = '#021016';
      ctx.shadowBlur = 12;
      // grass
      for (let i=0; i<14; i++) {
        const x = 40 + i * 65 + Math.sin(i)*18;
        ctx.beginPath();
        ctx.moveTo(x, 530);
        ctx.quadraticCurveTo(x-20, 420+Math.sin(i*2+Date.now()*0.001)*12, x+15, 340+Math.sin(i*1.3)*8);
        ctx.strokeStyle = '#236b4a';
        ctx.lineWidth = 6;
        ctx.stroke();
      }
      // rocks
      ctx.shadowBlur = 8;
      ctx.fillStyle = '#3f5a64';
      ctx.beginPath();
      ctx.ellipse(780, 500, 45, 25, 0, 0, Math.PI*2);
      ctx.fill();
      ctx.fillStyle = '#2f4a55';
      ctx.beginPath();
      ctx.ellipse(150, 520, 30, 18, 0.2, 0, Math.PI*2);
      ctx.fill();

      ctx.shadowBlur = 0;

      // ----- draw food pellets -----
      for (let p of foodPellets) {
        const alpha = p.age > 6 ? Math.max(0, 1 - (p.age-6)/3) : 1.0;
        ctx.globalAlpha = alpha * 0.95;
        ctx.shadowBlur = 18;
        ctx.shadowColor = '#fce9b0';
        // pellet gradient
        const rad = p.size * 0.8;
        const grd = ctx.createRadialGradient(p.x-2, p.y-2, 1, p.x, p.y, rad+2);
        grd.addColorStop(0, '#ffe68f');
        grd.addColorStop(0.5, '#dbaa4a');
        grd.addColorStop(1, '#8f6a2a');
        ctx.fillStyle = grd;
        ctx.beginPath();
        ctx.arc(p.x, p.y, rad, 0, Math.PI*2);
        ctx.fill();
        // sparkle
        ctx.shadowBlur = 6;
        ctx.fillStyle = '#fffbe6';
        ctx.beginPath();
        ctx.arc(p.x-2, p.y-3, 2, 0, Math.PI*2);
        ctx.fill();
      }
      ctx.globalAlpha = 1.0;
      ctx.shadowBlur = 0;

      // ----- draw fish (with realistic details) -----
      for (let f of fish) {
        const angle = f.angle;
        const size = f.size;
        const bodyLen = size * 2.2;
        const tailLen = size * 0.9;

        ctx.save();
        ctx.translate(f.x, f.y);
        ctx.rotate(angle);

        // shadow / depth
        ctx.shadowBlur = 12;
        ctx.shadowColor = 'rgba(0,20,30,0.5)';

        // ---- tail ----
        const tailWag = Math.sin(f.tailPhase) * 0.25;
        ctx.save();
        ctx.translate(-bodyLen * 0.7, 0);
        ctx.rotate(tailWag);
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.lineTo(-tailLen, -size*0.7);
        ctx.lineTo(-tailLen * 0.7, 0);
        ctx.lineTo(-tailLen, size*0.7);
        ctx.closePath();
        ctx.fillStyle = f.finColor;
        ctx.fill();
        ctx.restore();

        // ---- body (ellipse) ----
        ctx.shadowBlur = 14;
        const bodyGrad = ctx.createRadialGradient(0, -size*0.2, size*0.3, 0, 0, size*1.0);
        bodyGrad.addColorStop(0, lightenColor(f.bodyColor, 30));
        bodyGrad.addColorStop(0.7, f.bodyColor);
        bodyGrad.addColorStop(1, darkenColor(f.bodyColor, 30));
        ctx.fillStyle = bodyGrad;
        ctx.beginPath();
        ctx.ellipse(0, 0, bodyLen*0.5, size*0.7, 0, 0, Math.PI*2);
        ctx.fill();

        // ---- dorsal fin ----
        ctx.beginPath();
        ctx.moveTo(-bodyLen*0.1, -size*0.55);
        ctx.lineTo(bodyLen*0.1, -size*0.9);
        ctx.lineTo(bodyLen*0.3, -size*0.5);
        ctx.fillStyle = f.finColor;
        ctx.globalAlpha = 0.7;
        ctx.fill();
        ctx.globalAlpha = 1.0;

        // ---- eye ----
        ctx.shadowBlur = 4;
        ctx.fillStyle = '#f5f9ff';
        ctx.beginPath();
        ctx.arc(bodyLen*0.25, -size*0.2, size*0.2, 0, Math.PI*2);
        ctx.fill();
        ctx.fillStyle = f.eyeColor;
        ctx.beginPath();
        ctx.arc(bodyLen*0.3, -size*0.18, size*0.1, 0, Math.PI*2);
        ctx.fill();
        ctx.fillStyle = 'white';
        ctx.beginPath();
        ctx.arc(bodyLen*0.33, -size*0.25, size*0.05, 0, Math.PI*2);
        ctx.fill();

        // ---- mouth ----
        ctx.beginPath();
        ctx.strokeStyle = '#1d1b1b';
        ctx.lineWidth = 1.5;
        ctx.arc(bodyLen*0.45, 0.8, size*0.12, 0, Math.PI*0.8);
        ctx.stroke();

        ctx.restore();
        ctx.shadowBlur = 0;
      }

      // bubble particles for atmosphere
      ctx.fillStyle = '#dcf2ff';
      ctx.globalAlpha = 0.08;
      for (let i=0; i<30; i++) {
        const x = 30 + i*30 + Math.sin(i*2+Date.now()*0.0004)*8;
        const y = 400 + Math.sin(i*3+Date.now()*0.001)*50;
        ctx.beginPath();
        ctx.arc(x, y, 2+Math.sin(i)*1.5, 0, Math.PI*2);
        ctx.fill();
      }
      ctx.globalAlpha = 1.0;
    }

    // ---- color helpers ----
    function lightenColor(color, percent) {
      const num = parseInt(color.replace('#',''), 16);
      const amt = Math.round(2.55 * percent);
      const R = Math.min(255, (num >> 16) + amt);
      const G = Math.min(255, ((num >> 8) & 0x00FF) + amt);
      const B = Math.min(255, (num & 0x0000FF) + amt);
      return `rgb(${R},${G},${B})`;
    }
    function darkenColor(color, percent) {
      const num = parseInt(color.replace('#',''), 16);
      const amt = Math.round(2.55 * percent);
      const R = Math.max(0, (num >> 16) - amt);
      const G = Math.max(0, ((num >> 8) & 0x00FF) - amt);
      const B = Math.max(0, (num & 0x0000FF) - amt);
      return `rgb(${R},${G},${B})`;
    }

    // ----- animation loop -----
    function animate() {
      updateFish();
      drawAquarium();
      requestAnimationFrame(animate);
    }
    animate();

    // ----- event: left click to add food -----
    canvas.addEventListener('click', (e) => {
      const rect = canvas.getBoundingClientRect();
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;
      const mouseX = (e.clientX - rect.left) * scaleX;
      const mouseY = (e.clientY - rect.top) * scaleY;
      addFood(mouseX, mouseY);
    });

    // (optional) right click prevent
    canvas.addEventListener('contextmenu', (e) => e.preventDefault());
  })();
</script>
</body>
</html>
```
### Aquarium Interaction & Fish Behavior
Click anywhere in the tank to add food, and watch the fish respond. Here's how it works:
*   **Feeding & Chasing:** Each fish will always swim toward the food pellet that is closest to it. When a fish reaches a pellet, it eats it, and the pellet disappears.
*   **Natural Swimming:** When no food is present, the fish will wander around the tank with gentle, realistic movements, including soft turns and tail wags.
*   **Visual Variety:** The 19 fish in the tank each have a unique color from a vibrant palette and vary in size, making the aquarium feel lively and diverse.

This is a single-file HTML clock application that creates a minimalist wall clock with a 3D effect, displaying Beijing time, date, and smooth second-hand movement.
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>minimal · shanghai wall clock</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      background: #f5f7fa;
      font-family: 'Segoe UI', Roboto, system-ui, -apple-system, sans-serif;
    }
    /* main clock container – circle with 3D shadow */
    .clock {
      position: relative;
      width: 380px;
      height: 380px;
      border-radius: 50%;
      background: #ffffff;
      box-shadow: 0 20px 35px rgba(0, 0, 0, 0.2), 0 8px 12px rgba(0, 0, 0, 0.1), inset 0 -2px 4px rgba(0,0,0,0.02);
      border: 12px solid #2d2d3a;
      display: flex;
      justify-content: center;
      align-items: center;
      transition: box-shadow 0.1s;
    }
    /* relative wrapper for hands & scale */
    .clock-face {
      position: relative;
      width: 94%;
      height: 94%;
      border-radius: 50%;
    }

    /* ---- SCALE & NUMBERS (60 ticks, hour marks thicker) ---- */
    .scale-container {
      position: absolute;
      width: 100%;
      height: 100%;
      top: 0;
      left: 0;
    }

    /* each tick element, rotated via JS style */
    .tick {
      position: absolute;
      top: 0;
      left: 50%;
      width: 2px;
      height: 100%;
      transform-origin: 50% 50%;
      pointer-events: none;
    }
    .tick-inner {
      position: absolute;
      top: 6px;          /* distance from rim */
      left: 50%;
      transform: translateX(-50%);
      width: 2px;
      height: 12px;
      background: #9aa9b7;
      border-radius: 1px;
    }
    /* thicker & darker for exact hour (every 5th tick) */
    .tick.hour .tick-inner {
      width: 3.2px;
      height: 18px;
      background: #1e262e;
      top: 4px;
      border-radius: 2px;
    }

    /* clock numbers: 1–12, positioned elegantly */
    .number {
      position: absolute;
      width: 30px;
      height: 30px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-weight: 400;
      font-size: 1.05rem;
      color: #222933;
      letter-spacing: 0.3px;
      transform: translate(-50%, -50%);
      pointer-events: none;
      font-variant-numeric: tabular-nums;
    }

    /* ---- HANDS ---- */
    .hand {
      position: absolute;
      bottom: 50%;
      left: 50%;
      transform-origin: 50% 100%;
      border-radius: 4px;
      pointer-events: none;
      transition: none; 
      /* smooth second hand via js requestAnimationFrame */
    }
    .hour-hand {
      width: 5px;
      height: 30%;
      margin-left: -2.5px;
      background: #1e232b;
      border-radius: 3px 3px 2px 2px;
      box-shadow: 0 0 3px rgba(0,0,0,0.08);
      transform: rotate(0deg);
      z-index: 5;
    }
    .minute-hand {
      width: 3.8px;
      height: 42%;
      margin-left: -1.9px;
      background: #1f262e;
      border-radius: 3px 3px 2px 2px;
      box-shadow: 0 0 3px rgba(0,0,0,0.06);
      transform: rotate(0deg);
      z-index: 6;
    }
    .second-hand {
      width: 2px;
      height: 44%;
      margin-left: -1px;
      background: #d33b3b;
      border-radius: 2px 2px 1px 1px;
      box-shadow: 0 0 5px rgba(200, 40, 40, 0.2);
      transform: rotate(0deg);
      z-index: 7;
    }
    /* center dot */
    .center-dot {
      position: absolute;
      width: 12px;
      height: 12px;
      background: #1b1f26;
      border-radius: 50%;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      z-index: 10;
      box-shadow: 0 0 4px rgba(0,0,0,0.1);
    }
    .center-dot::after {
      content: '';
      position: absolute;
      width: 4px;
      height: 4px;
      background: #eceaea;
      border-radius: 50%;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
    }

    /* ---- TEXT DISPLAY (upper / lower) ---- */
    .info-top {
      position: absolute;
      top: 24%;
      left: 50%;
      transform: translate(-50%, -50%);
      font-size: 2.8rem;
      font-weight: 500;
      letter-spacing: 1.5px;
      color: #181e26;
      background: rgba(245, 247, 250, 0.15);
      padding: 0.1rem 1.8rem;
      border-radius: 40px;
      backdrop-filter: blur(1px);
      white-space: nowrap;
      font-family: 'Segoe UI', Roboto, sans-serif;
      font-variant-numeric: tabular-nums;
      text-shadow: 0 1px 1px rgba(255,255,255,0.6);
      z-index: 20;
    }
    .info-bottom {
      position: absolute;
      bottom: 24%;
      left: 50%;
      transform: translate(-50%, 50%);
      font-size: 1.25rem;
      font-weight: 400;
      color: #1f282f;
      background: rgba(235, 240, 245, 0.2);
      padding: 0.2rem 2rem;
      border-radius: 40px;
      backdrop-filter: blur(1px);
      letter-spacing: 0.8px;
      white-space: nowrap;
      font-family: 'Segoe UI', Roboto, sans-serif;
      text-shadow: 0 1px 2px rgba(255,255,255,0.5);
      z-index: 20;
    }

    /* subtle responsiveness */
    @media (max-width: 420px) {
      .clock { width: 320px; height: 320px; border-width: 8px; }
      .info-top { font-size: 2.2rem; top: 22%; }
      .info-bottom { font-size: 1rem; bottom: 22%; }
    }
  </style>
</head>
<body>
<div class="clock">
  <div class="clock-face" id="clockFace">
    <!-- Scales & numbers will be injected by JS -->
    <div class="scale-container" id="scaleContainer"></div>

    <!-- Hands -->
    <div class="hand hour-hand" id="hourHand"></div>
    <div class="hand minute-hand" id="minuteHand"></div>
    <div class="hand second-hand" id="secondHand"></div>
    <div class="center-dot"></div>

    <!-- Text displays -->
    <div class="info-top" id="timeDisplay">00:00:00</div>
    <div class="info-bottom" id="dateDisplay">---</div>
  </div>
</div>

<script>
  (function() {
    // ----- BUILD SCALE (60 ticks) & CLOCK NUMBERS (1–12) -----
    const container = document.getElementById('scaleContainer');
    const face = document.getElementById('clockFace');
    const fragment = document.createDocumentFragment();

    // 60 ticks (0..59)
    for (let i = 0; i < 60; i++) {
      const tick = document.createElement('div');
      tick.className = 'tick';
      // every 5th tick = hour marker
      if (i % 5 === 0) {
        tick.classList.add('hour');
      }
      const inner = document.createElement('div');
      inner.className = 'tick-inner';
      tick.appendChild(inner);
      // rotation: i * 6°
      const angle = i * 6;
      tick.style.transform = `rotate(${angle}deg)`;
      fragment.appendChild(tick);
    }

    // add numbers 1..12 (positioned via trigonometric)
    for (let n = 1; n <= 12; n++) {
      const numEl = document.createElement('div');
      numEl.className = 'number';
      // angle per hour: 30° (but start at -90° to place 12 at top)
      const angleDeg = (n * 30) - 90; 
      const rad = angleDeg * Math.PI / 180;
      const radius = 38; // percentage of container size (38% from center to number)
      const parentSize = 94; // clock-face relative size
      // convert to percentage relative to parent
      const x = 50 + radius * Math.cos(rad);
      const y = 50 + radius * Math.sin(rad);
      numEl.style.left = `${x}%`;
      numEl.style.top = `${y}%`;
      numEl.textContent = n;
      fragment.appendChild(numEl);
    }
    container.appendChild(fragment);

    // ----- HANDS REFERENCES -----
    const hourHand = document.getElementById('hourHand');
    const minuteHand = document.getElementById('minuteHand');
    const secondHand = document.getElementById('secondHand');
    const timeDisplay = document.getElementById('timeDisplay');
    const dateDisplay = document.getElementById('dateDisplay');

    // ----- TIME UPDATE (Shanghai / Beijing time UTC+8) -----
    function updateClock() {
      // get current time in Asia/Shanghai (Beijing time)
      const now = new Date();
      // using toLocaleString to parse shanghai time reliably
      const shanghaiString = now.toLocaleString("en-US", { timeZone: "Asia/Shanghai" });
      // parse: "MM/DD/YYYY, HH:MM:SS AM/PM" (en-US format)
      const parsed = new Date(shanghaiString);
      // if parsing fails (edge case) fallback to UTC+8 offset
      let year, month, day, hours, minutes, seconds, weekdayIndex;
      if (!isNaN(parsed.getTime())) {
        year = parsed.getFullYear();
        month = parsed.getMonth() + 1;
        day = parsed.getDate();
        hours = parsed.getHours();
        minutes = parsed.getMinutes();
        seconds = parsed.getSeconds();
        weekdayIndex = parsed.getDay(); // 0=Sun
      } else {
        // fallback: compute manually
        const utc = now.getTime() + now.getTimezoneOffset() * 60000;
        const shanghaiTime = new Date(utc + 8 * 3600000);
        year = shanghaiTime.getFullYear();
        month = shanghaiTime.getMonth() + 1;
        day = shanghaiTime.getDate();
        hours = shanghaiTime.getHours();
        minutes = shanghaiTime.getMinutes();
        seconds = shanghaiTime.getSeconds();
        weekdayIndex = shanghaiTime.getDay();
      }

      // --- smooth second hand (including millisecond interpolation) ---
      // get milliseconds for smooth motion
      const ms = new Date().getMilliseconds();
      // but we want continuity: seconds + ms/1000
      const smoothSec = seconds + ms / 1000;
      // angles
      const hourAngle = (hours % 12) * 30 + minutes * 0.5 + (seconds / 120); // 0.5° per minute + sec contribution
      const minuteAngle = minutes * 6 + seconds * 0.1; // 0.1° per second
      const secondAngle = smoothSec * 6; // 360°/60 = 6° per second

      // apply rotation
      hourHand.style.transform = `rotate(${hourAngle}deg)`;
      minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
      secondHand.style.transform = `rotate(${secondAngle}deg)`;

      // format time (24h) with leading zeros
      const hh = String(hours).padStart(2, '0');
      const mm = String(minutes).padStart(2, '0');
      const ss = String(seconds).padStart(2, '0');
      timeDisplay.textContent = `${hh}:${mm}:${ss}`;

      // date & weekday
      const weekdays = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
      const weekdayName = weekdays[weekdayIndex] || '';
      const monthStr = String(month).padStart(2, '0');
      const dayStr = String(day).padStart(2, '0');
      dateDisplay.textContent = `${year}.${monthStr}.${dayStr} • ${weekdayName}`;
    }

    // use requestAnimationFrame for smooth second hand
    let lastTimestamp = 0;
    function tickLoop(timestamp) {
      // update every frame ~60fps -> smooth second hand
      updateClock();
      requestAnimationFrame(tickLoop);
    }
    // start loop
    requestAnimationFrame(tickLoop);

    // extra interval for safety (update even if rAF stutters)
    setInterval(() => {
      // but updateClock already called by rAF; just a backup (small overhead)
      // to avoid double update we can leave it, but rAF is primary.
      // however, updates are cheap so fine.
    }, 500);

    // initial update
    updateClock();
  })();
</script>
</body>
</html>
