            <div class="form-group">
                <label for="noteTitle">Title *</label>
                <input type="text" id="noteTitle" required>
            </div>
            <div class="form-group">
                <label for="noteOwner">Owner *</label>
                <input type="text" id="noteOwner" required>
            </div>
