    /* filter bar */
    .filter-bar {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      gap: 0.8rem 1.5rem;
      background: white;
      padding: 0.9rem 1.8rem;
      border-radius: 40px;
      margin-bottom: 2rem;
      box-shadow: 0 2px 8px rgba(0,0,0,0.02);
