    .filter-group {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      flex-wrap: wrap;
    }

    .filter-group label {
      font-size: 0.8rem;
      white-space: nowrap;
    }

    .filter-group select, .filter-group input {
      padding: 0.4rem 0.8rem;
      border-radius: 30px;
      border: 1px solid #d1d9e6;
      background: white;
      min-width: 120px;
    }

    .filter-group input {
      min-width: 180px;
    }

    /* notes grid */
    .notes-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 1.5rem;
    }

    @media (max-width: 750px) {
      .notes-grid {
        grid-template-columns: 1fr;
      }
      .stats-strip {
        gap: 0.8rem 1.5rem;
      }
    }

    .note-card {
      background: white;
      border-radius: 24px;
      padding: 1.6rem;
      box-shadow: 0 8px 20px rgba(0,0,0,0.03);
      border: 1px solid #eef2f6;
      transition: box-shadow 0.2s;
      display: flex;
      flex-direction: column;
      gap: 0.75rem;
    }

    .note-card:hover {
      box-shadow: 0 12px 28px rgba(0,0,0,0.06);
    }

    .note-header {
      display: flex;
      flex-wrap: wrap;
      justify-content: space-between;
      align-items: baseline;
      gap: 0.6rem;
