    .note-footer {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      justify-content: space-between;
      margin-top: 0.4rem;
      gap: 0.6rem;
    }

    .note-actions {
      display: flex;
      gap: 0.4rem;
    }

    .type-badge {
      font-size: 0.75rem;
      font-weight: 600;
      padding: 0.25rem 1rem;
      border-radius: 30px;
      background: #f1f5f9;
      color: #1e293b;
      text-transform: uppercase;
      letter-spacing: 0.03em;
    }

    .type-badge.action {
      background: #fee2e2;
      color: #991b1b;
    }
    .type-badge.decision {
      background: #e0f2fe;
      color: #075985;
    }
    .type-badge.reference {
      background: #f1f5f9;
      color: #334155;
    }

    .empty-notes {
      grid-column: 1 / -1;
      background: white;
      border-radius: 30px;
      padding: 2.5rem;
      text-align: center;
      border: 1px dashed #cbd5e1;
      color: #64748b;
    }

    hr {
      border: 0;
