<script>
    (function(){
        const canvas = document.getElementById('aquariumCanvas');
        const ctx = canvas.getContext('2d');
        const foodCountSpan = document.getElementById('foodCount');

        // 尺寸参数
        const W = 900, H = 600;

        // ----- 鱼的数据 -----
        const FISH_COUNT = 11;
        let fishes = [];

        // ----- 鱼食数据 -----
