        0 18px 30px -10px rgba(0, 0, 0, 0.15),
        0 8px 20px rgba(0, 0, 0, 0.05),
        inset 0 1px 2px rgba(255, 255, 255, 0.6);
      border: 1px solid rgba(0, 0, 0, 0.06);
      transition: box-shadow 0.2s;
    }

    .clock-container {
      position: relative;
      width: 340px;
      height: 340px;
      margin: 0 auto;
