      box-shadow: 
        0 12px 28px -8px rgba(0, 0, 0, 0.2),
        0 0 0 1px rgba(0, 0, 0, 0.08),
        inset 0 -2px 4px rgba(0,0,0,0.02);
      transition: box-shadow 0.3s;
      cursor: default;
