            cursor: pointer;
        }
        .btn-cancel {
            background: #eef2f6;
            color: #1e293b;
        }
        .btn-cancel:hover { background: #dce2ec; }
        .btn-submit {
            background: #1e3a5f;
            color: white;
        }
        .btn-submit:hover { background: #0f2c47; }

        /* 响应式：窄屏三列纵向 */
        @media (max-width: 720px) {
            .board {
                flex-direction: column;
                gap: 24px;
            }
            .filter-bar {
                border-radius: 30px;
                padding: 16px;
                flex-direction: column;
                align-items: stretch;
