      if (document.hidden) {
        // 如果隐藏, 仍然更新时间, 但不会太频繁
        updateClock();
      }
    }, 500);

    // 页面可见性变化时立即刷新一次
    document.addEventListener('visibilitychange', () => {
      if (!document.hidden) {
        updateClock();
      }
    });

    // 窗口缩放时数字位置不受影响 (使用百分比)
    // 但为了更好适应, 监听 resize 稍微微调 (无需)
    console.log('🕰️ 极简挂钟已启动 · 北京时间');
  })();
</script>
