    <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
    <title>高级感 · 北京时区时钟</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            background: linear-gradient(145deg, #f0f2f5 0%, #e6e9f0 100%);
            display: flex;
