            const localeString = now.toLocaleString("en-US", { timeZone: "Asia/Shanghai" });
            // parse: "M/D/YYYY, H:MM:SS" or "M/D/YYYY, H:MM:SS AM" -> we avoid AM/PM by using en-US with hourCycle: 24?
            // but to be safe: we directly parse from known format using Date or custom parsing.
            // Alternative: use Intl.DateTimeFormat for reliable 24h.
            // Better: format to ISO parts. Use Intl for hour, minute, second separately.
            const timeZone = 'Asia/Shanghai';
            const formatter = new Intl.DateTimeFormat('en-US', {
                timeZone,
                hour: '2-digit', minute: '2-digit', second: '2-digit',
                hour12: false,
                year: 'numeric', month: '2-digit', day: '2-digit',
                weekday: 'long'
            });
            const parts = formatter.formatToParts(now);
            // build time object
            let data = { year: '', month: '', day: '', hour: '00', minute: '00', second: '00', weekday: '' };
            for (const part of parts) {
                if (part.type === 'year') data.year = part.value;
                if (part.type === 'month') data.month = part.value;
                if (part.type === 'day') data.day = part.value;
                if (part.type === 'hour') data.hour = part.value;
                if (part.type === 'minute') data.minute = part.value;
                if (part.type === 'second') data.second = part.value;
                if (part.type === 'weekday') data.weekday = part.value;
            }

            // --- compute angles (smooth second) ---
            const hours = parseInt(data.hour, 10);
            const minutes = parseInt(data.minute, 10);
            const seconds = parseInt(data.second, 10);
            // seconds with millisecond for smooth motion (use local milliseconds after sync)
            const nowMs = now.getTime();
            // But to keep in sync with Shanghai, we need ms difference? Use directly getMilliseconds() but date is local.
            // However, the second hand smoothness: we can recompute using milliseconds from the date object (local) 
            // but the second value from formatter is integer. We'll recalc ms from the same 'now' Date (UTC based) 
            // but the time difference is fixed. Get ms from the date object and apply UTC offset? Simpler:
            // Use now.getMilliseconds() (local) for sub-second smoothness. For Shanghai, the offset difference is constant,
            // but ms remains same across timezones. So we can use now.getMilliseconds() to create smooth second.
            const ms = now.getMilliseconds();
            const exactSeconds = seconds + ms / 1000;
            // minute + exact seconds
            const minuteAngle = (minutes + exactSeconds / 60) * 6;
            const hourAngle = ((hours % 12) + minutes / 60 + exactSeconds / 3600) * 30;
            const secondAngle = exactSeconds * 6;   // 360° / 60 = 6°

