            // 24h format with leading zeros (already from formatter)
            const timeStr = `${data.hour}:${data.minute}:${data.second}`;
            timeDisplay.textContent = timeStr;

            // date / week: "2025-03-21  Friday" (style)
            const dateStr = `${data.year}-${data.month}-${data.day}`;
            const weekStr = data.weekday || '';
            dateDisplay.textContent = `${dateStr}  ${weekStr}`;
